"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { signIn } from "next-auth/react";
import Image from "next/image";

export default function LoginPage() {
  const router = useRouter();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    try {
      const result = await signIn("credentials", {
        email,
        password,
        redirect: false,
      });

      if (result?.error) {
        setError("Invalid email or password");
      } else {
        router.push("/dashboard");
        router.refresh();
      }
    } catch (err) {
      setError("An unexpected error occurred. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="relative flex min-h-screen overflow-hidden">
      {/* Animated background particles effect */}
      <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_top_left,_var(--tw-gradient-stops))] from-purple-900/40 via-[#0a0e27] to-[#0a0e27]" />
      <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_bottom_right,_var(--tw-gradient-stops))] from-cyan-900/30 via-transparent to-transparent" />
      <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_center,_var(--tw-gradient-stops))] from-blue-900/20 via-transparent to-transparent" />

      {/* Decorative glowing orbs */}
      <div className="absolute -left-32 -top-32 h-96 w-96 rounded-full bg-purple-600/10 blur-3xl" />
      <div className="absolute -bottom-32 -right-32 h-96 w-96 rounded-full bg-cyan-500/10 blur-3xl" />
      <div className="absolute left-1/2 top-1/3 h-64 w-64 -translate-x-1/2 rounded-full bg-blue-500/5 blur-3xl" />

      {/* Content */}
      <div className="relative z-10 flex w-full">
        {/* Left panel – Branding */}
        <div className="hidden lg:flex lg:w-1/2 flex-col items-center justify-center p-12">
          <div className="flex flex-col items-center space-y-8">
            {/* Logo */}
            <div className="relative">
              <div className="absolute -inset-4 rounded-full bg-gradient-to-r from-purple-500/20 via-blue-500/20 to-cyan-500/20 blur-2xl" />
              <Image
                src="/robust-6g-logo.png"
                alt="ROBUST-6G Logo"
                width={280}
                height={280}
                className="relative drop-shadow-2xl"
                priority
              />
            </div>

            {/* Tagline */}
            <div className="text-center space-y-4">
              <p className="text-lg text-blue-200/80 max-w-md leading-relaxed">
                Next-Generation Network Intelligence Platform
              </p>
              <div className="h-px w-48 mx-auto bg-gradient-to-r from-transparent via-cyan-400/50 to-transparent" />
            </div>

            {/* Stats */}
            <div className="flex gap-12 pt-4">
              <div className="text-center">
                <p className="text-2xl font-bold bg-gradient-to-r from-cyan-300 to-blue-300 bg-clip-text text-transparent">
                  99.9%
                </p>
                <p className="text-xs text-blue-300/60 mt-1 uppercase tracking-wider">
                  Uptime
                </p>
              </div>
              <div className="text-center">
                <p className="text-2xl font-bold bg-gradient-to-r from-purple-300 to-cyan-300 bg-clip-text text-transparent">
                  &lt;1ms
                </p>
                <p className="text-xs text-blue-300/60 mt-1 uppercase tracking-wider">
                  Latency
                </p>
              </div>
              <div className="text-center">
                <p className="text-2xl font-bold bg-gradient-to-r from-blue-300 to-purple-300 bg-clip-text text-transparent">
                  24/7
                </p>
                <p className="text-xs text-blue-300/60 mt-1 uppercase tracking-wider">
                  Monitoring
                </p>
              </div>
            </div>
          </div>
        </div>

        {/* Right panel – Login form */}
        <div className="flex w-full items-center justify-center px-6 lg:w-1/2">
          <div className="w-full max-w-md space-y-8">
            {/* Glass card */}
            <div className="rounded-2xl border border-white/10 bg-white/5 p-8 shadow-2xl backdrop-blur-xl">
              {/* Mobile logo */}
              <div className="mb-8 text-center lg:hidden">
                <Image
                  src="/robust-6g-logo.png"
                  alt="ROBUST-6G Logo"
                  width={160}
                  height={160}
                  className="mx-auto drop-shadow-xl"
                  priority
                />
              </div>

              {/* Header */}
              <div className="mb-8 text-center lg:text-left">
                <h2 className="text-2xl font-bold tracking-tight text-white">
                  Welcome back
                </h2>
                <p className="mt-2 text-sm text-blue-200/60">
                  Sign in to access your dashboard
                </p>
              </div>

              {/* Form */}
              <form onSubmit={handleSubmit} className="space-y-5">
                {error && (
                  <div className="flex items-center gap-2 rounded-lg border border-red-500/30 bg-red-500/10 p-4 text-sm text-red-300 backdrop-blur-sm">
                    <svg
                      className="h-5 w-5 flex-shrink-0"
                      viewBox="0 0 20 20"
                      fill="currentColor"
                    >
                      <path
                        fillRule="evenodd"
                        d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.28 7.22a.75.75 0 00-1.06 1.06L8.94 10l-1.72 1.72a.75.75 0 101.06 1.06L10 11.06l1.72 1.72a.75.75 0 101.06-1.06L11.06 10l1.72-1.72a.75.75 0 00-1.06-1.06L10 8.94 8.28 7.22z"
                        clipRule="evenodd"
                      />
                    </svg>
                    {error}
                  </div>
                )}

                <div>
                  <label
                    htmlFor="email"
                    className="block text-sm font-medium text-blue-100/80"
                  >
                    Email address
                  </label>
                  <input
                    id="email"
                    type="email"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    required
                    autoComplete="email"
                    placeholder="you@robust-6g.eu"
                    className="mt-1.5 block w-full rounded-lg border border-white/10 bg-white/5 px-4 py-3 text-white shadow-sm placeholder:text-blue-300/30 focus:border-cyan-400/50 focus:outline-none focus:ring-2 focus:ring-cyan-400/20 backdrop-blur-sm transition-all"
                  />
                </div>

                <div>
                  <label
                    htmlFor="password"
                    className="block text-sm font-medium text-blue-100/80"
                  >
                    Password
                  </label>
                  <input
                    id="password"
                    type="password"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    required
                    autoComplete="current-password"
                    placeholder="••••••••"
                    className="mt-1.5 block w-full rounded-lg border border-white/10 bg-white/5 px-4 py-3 text-white shadow-sm placeholder:text-blue-300/30 focus:border-cyan-400/50 focus:outline-none focus:ring-2 focus:ring-cyan-400/20 backdrop-blur-sm transition-all"
                  />
                </div>

                <button
                  type="submit"
                  disabled={loading}
                  className="w-full rounded-lg bg-gradient-to-r from-purple-600 via-blue-600 to-cyan-600 px-4 py-3 text-sm font-semibold text-white shadow-lg shadow-blue-500/25 hover:from-purple-500 hover:via-blue-500 hover:to-cyan-500 focus:outline-none focus:ring-2 focus:ring-cyan-400/50 focus:ring-offset-2 focus:ring-offset-[#0a0e27] disabled:cursor-not-allowed disabled:opacity-50 transition-all duration-300"
                >
                  {loading ? (
                    <span className="flex items-center justify-center gap-2">
                      <svg
                        className="h-4 w-4 animate-spin"
                        viewBox="0 0 24 24"
                        fill="none"
                      >
                        <circle
                          className="opacity-25"
                          cx="12"
                          cy="12"
                          r="10"
                          stroke="currentColor"
                          strokeWidth="4"
                        />
                        <path
                          className="opacity-75"
                          fill="currentColor"
                          d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"
                        />
                      </svg>
                      Signing in...
                    </span>
                  ) : (
                    "Sign in"
                  )}
                </button>

                {/* Domain policy */}
                <div className="rounded-lg border border-cyan-400/10 bg-cyan-400/5 p-4 backdrop-blur-sm">
                  <p className="text-center text-xs text-cyan-200/60">
                    <span className="font-medium text-cyan-200/80">
                      Organization policy:
                    </span>{" "}
                    Only emails affiliated with{" "}
                    <span className="font-semibold text-cyan-300">
                      ROBUST-6G
                    </span>{" "}
                    are allowed.
                  </p>
                  <p className="mt-1 text-center text-xs text-cyan-300/40">
                    Accepted domains:{" "}
                    <span className="font-mono font-medium text-cyan-300/60">
                      robust-6g.eu
                    </span>
                    ,{" "}
                    <span className="font-mono font-medium text-cyan-300/60">
                      robust-6g.org
                    </span>
                  </p>
                </div>
              </form>
            </div>

            {/* Footer */}
            <p className="text-center text-xs text-blue-300/30">
              © {new Date().getFullYear()} ROBUST-6G. All rights reserved.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}